compliant:
// Split into focused structures
struct PersonBasic {
  char firstName[50];
  char lastName[50];
  int age;
};

struct PersonContact {
  char email[100];
  char phone[20];
  struct Address address;
};

struct PersonMedical {
  char bloodType[5];
  char allergies[200];
  char medications[300];
};

struct SimpleConfig {  // Compliant: reasonable number of fields
  int timeout;
  char hostname[64];
  int port;
  bool useSSL;
};
